// ============================================================
// HydraNet - Team Members API Route
// Manage engineers assigned to a team
// ============================================================

import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/prisma'

interface RouteParams {
  params: Promise<{ id: string }>
}

// GET /api/teams/[id]/members - Get team with members
export async function GET(request: NextRequest, { params }: RouteParams) {
  try {
    const { id } = await params

    const team = await prisma.team.findUnique({
      where: { id },
      include: {
        branch: {
          select: { id: true, name: true, utilityId: true, dmaId: true },
        },
        dma: {
          select: { id: true, name: true, utilityId: true },
        },
        leader: {
          select: { id: true, name: true, email: true, phone: true, role: true, status: true },
        },
        engineers: {
          select: { id: true, name: true, email: true, phone: true, role: true, status: true },
          orderBy: { name: 'asc' },
        },
      },
    })

    if (!team) {
      return NextResponse.json({ error: 'Team not found' }, { status: 404 })
    }

    // Get eligible engineers (same utility, DMA, and branch, active, not in any team or in this team)
    const eligibleEngineers = await prisma.engineer.findMany({
      where: {
        branchId: team.branchId,
        dmaId: team.dmaId,
        status: 'active',
        OR: [
          { teamId: null },
          { teamId: id },
        ],
      },
      select: {
        id: true,
        name: true,
        email: true,
        phone: true,
        role: true,
        status: true,
        teamId: true,
      },
      orderBy: { name: 'asc' },
    })

    return NextResponse.json({
      team: {
        ...team,
        branchName: team.branch.name,
        dmaName: team.dma.name,
        utilityId: team.branch.utilityId,
      },
      eligibleEngineers,
      currentMemberIds: team.engineers.map(e => e.id),
    })
  } catch (error) {
    console.error('Error fetching team members:', error)
    return NextResponse.json({ error: 'Failed to fetch team members' }, { status: 500 })
  }
}

// POST /api/teams/[id]/members - Add engineers to team
export async function POST(request: NextRequest, { params }: RouteParams) {
  try {
    const { id } = await params
    const data = await request.json()
    const { engineerIds } = data

    if (!engineerIds || !Array.isArray(engineerIds) || engineerIds.length === 0) {
      return NextResponse.json({ error: 'Engineer IDs are required' }, { status: 400 })
    }

    // Check if team exists
    const team = await prisma.team.findUnique({
      where: { id },
      include: {
        branch: { select: { id: true, utilityId: true, dmaId: true } },
      },
    })

    if (!team) {
      return NextResponse.json({ error: 'Team not found' }, { status: 404 })
    }

    // Verify all engineers exist and are eligible
    const engineers = await prisma.engineer.findMany({
      where: {
        id: { in: engineerIds },
      },
    })

    if (engineers.length !== engineerIds.length) {
      return NextResponse.json({ error: 'One or more engineers not found' }, { status: 404 })
    }

    // Check eligibility: same branch, DMA, and either no team or this team
    const ineligibleEngineers = engineers.filter(e => 
      e.branchId !== team.branchId ||
      e.dmaId !== team.dmaId ||
      (e.teamId !== null && e.teamId !== id)
    )

    if (ineligibleEngineers.length > 0) {
      const names = ineligibleEngineers.map(e => e.name).join(', ')
      return NextResponse.json(
        { error: `Engineers must have the same branch and DMA as the team, and not be in another team. Ineligible: ${names}` },
        { status: 400 }
      )
    }

    // Add engineers to team
    await prisma.engineer.updateMany({
      where: { id: { in: engineerIds } },
      data: { teamId: id },
    })

    // Fetch updated team
    const updatedTeam = await prisma.team.findUnique({
      where: { id },
      include: {
        branch: { select: { id: true, name: true, utilityId: true } },
        dma: { select: { id: true, name: true } },
        leader: { select: { id: true, name: true, email: true, role: true } },
        engineers: { select: { id: true, name: true, email: true, role: true, status: true } },
      },
    })

    return NextResponse.json({
      ...updatedTeam,
      branchName: updatedTeam!.branch.name,
      dmaName: updatedTeam!.dma.name,
      utilityId: updatedTeam!.branch.utilityId,
      leaderName: updatedTeam!.leader?.name,
      memberCount: updatedTeam!.engineers.length,
      engineerIds: updatedTeam!.engineers.map(e => e.id),
    })
  } catch (error) {
    console.error('Error adding team members:', error)
    return NextResponse.json({ error: 'Failed to add team members' }, { status: 500 })
  }
}

// DELETE /api/teams/[id]/members - Remove engineers from team
export async function DELETE(request: NextRequest, { params }: RouteParams) {
  try {
    const { id } = await params
    const { searchParams } = new URL(request.url)
    const engineerIds = searchParams.get('engineerIds')?.split(',')

    if (!engineerIds || engineerIds.length === 0) {
      return NextResponse.json({ error: 'Engineer IDs are required' }, { status: 400 })
    }

    // Check if team exists
    const team = await prisma.team.findUnique({
      where: { id },
      include: {
        leader: { select: { id: true } },
      },
    })

    if (!team) {
      return NextResponse.json({ error: 'Team not found' }, { status: 404 })
    }

    // Use transaction for atomic updates
    await prisma.$transaction(async (tx) => {
      for (const engineerId of engineerIds) {
        // If this engineer is the team leader, remove leader assignment
        if (team.leaderId === engineerId) {
          await tx.team.update({
            where: { id },
            data: { leaderId: null },
          })
          
          // Update the engineer's role back to engineer
          await tx.engineer.update({
            where: { id: engineerId },
            data: { 
              teamId: null,
              role: 'engineer',
            },
          })
        } else {
          // Just remove from team
          await tx.engineer.update({
            where: { id: engineerId },
            data: { teamId: null },
          })
        }
      }
    })

    // Fetch updated team
    const updatedTeam = await prisma.team.findUnique({
      where: { id },
      include: {
        branch: { select: { id: true, name: true, utilityId: true } },
        dma: { select: { id: true, name: true } },
        leader: { select: { id: true, name: true, email: true, role: true } },
        engineers: { select: { id: true, name: true, email: true, role: true, status: true } },
      },
    })

    return NextResponse.json({
      ...updatedTeam,
      branchName: updatedTeam!.branch.name,
      dmaName: updatedTeam!.dma.name,
      utilityId: updatedTeam!.branch.utilityId,
      leaderName: updatedTeam!.leader?.name,
      memberCount: updatedTeam!.engineers.length,
      engineerIds: updatedTeam!.engineers.map(e => e.id),
    })
  } catch (error) {
    console.error('Error removing team members:', error)
    return NextResponse.json({ error: 'Failed to remove team members' }, { status: 500 })
  }
}